    // Lista donde se acumula CADA error encontrado (sintáctico y semántico).
    // CompiladorJava.java la lee después de llamar a parser.parse().
    public List<String> errores = new ArrayList<>();

    public void syntax_error(Symbol s) {
        String tok = s.value != null ? s.value.toString() : "fin de entrada";
        errores.add("Error Sintáctico en L" + s.left
                + ": token inesperado '" + tok + "'");
    }

    public void unrecovered_syntax_error(Symbol s) throws java.lang.Exception {
        // No relanzamos excepción: detenemos limpiamente y dejamos que
        // CompiladorJava.java recoja todo lo que hay en `errores`.
        String tok = s.value != null ? s.value.toString() : "fin de entrada";
        errores.add("Error Irrecuperable en L" + s.left
                + ": no se puede continuar desde '" + tok
                + "'. Revisa la sintaxis en esa línea.");
        done_parsing();
    }


