    // Reglas de casteo implícito (widening). Sin cambios en lógica.
    public boolean esCompatible(String destino, String origen) {
        destino = destino.toUpperCase();
        origen  = origen.toUpperCase();

        if (destino.equals(origen))   return true;
        if (destino.equals("STRING")) return true; // concatenación siempre válida

        if (destino.equals("DOUBLE")) return origen.equals("FLOAT")  || origen.equals("LONG")
                                            || origen.equals("INT")   || origen.equals("SHORT")
                                            || origen.equals("BYTE")  || origen.equals("CHAR");
        if (destino.equals("FLOAT"))  return origen.equals("LONG")   || origen.equals("INT")
                                            || origen.equals("SHORT") || origen.equals("BYTE")
                                            || origen.equals("CHAR");
        if (destino.equals("LONG"))   return origen.equals("INT")    || origen.equals("SHORT")
                                            || origen.equals("BYTE")  || origen.equals("CHAR");
        if (destino.equals("INT"))    return origen.equals("SHORT")  || origen.equals("BYTE")
                                            || origen.equals("CHAR");
        if (destino.equals("SHORT"))  return origen.equals("BYTE");
        return false;
    }

    // Calcula el tipo resultante de una operación aritmética.
    // Ya NO lanza excepción — agrega el error y retorna "INT" como tipo seguro.
    public String tipoResultanteAritmetico(String t1, String t2, int linea) {
        if (t1.equals("BOOLEAN") || t2.equals("BOOLEAN")
                || t1.equals("STRING") || t2.equals("STRING")) {
            parser.errores.add("Error Semántico [Línea " + linea
                    + "]: Operación aritmética inválida entre tipos "
                    + t1 + " y " + t2 + ".");
            return "INT"; // tipo seguro para continuar
        }
        if (t1.equals("DOUBLE") || t2.equals("DOUBLE")) return "DOUBLE";
        if (t1.equals("FLOAT")  || t2.equals("FLOAT"))  return "FLOAT";
        if (t1.equals("LONG")   || t2.equals("LONG"))   return "LONG";
        return "INT";
    }

